def reciprocal_rank(retrieved_ids: list[str], relevant_ids: set[str]) -> float:
    """Return 1/rank of the first relevant document, or 0 if none found."""
    for rank, doc_id in enumerate(retrieved_ids, start=1):
        if doc_id in relevant_ids:
            return 1.0 / rank
    return 0.0


def mean_reciprocal_rank(eval_set: list[dict]) -> float:
    """
    eval_set: list of {"retrieved": [...doc_ids...], "relevant": set([...doc_ids...])}
    """
    rr_scores = [
        reciprocal_rank(item["retrieved"], item["relevant"])
        for item in eval_set
    ]
    return sum(rr_scores) / len(rr_scores) if rr_scores else 0.0


eval_data = [
    {"retrieved": ["doc_B", "doc_A", "doc_C"], "relevant": {"doc_A"}},  # RR = 0.5
    {"retrieved": ["doc_X", "doc_Y", "doc_A"], "relevant": {"doc_A"}},  # RR = 0.33
    {"retrieved": ["doc_A", "doc_B", "doc_C"], "relevant": {"doc_A"}},  # RR = 1.0
]

mrr = mean_reciprocal_rank(eval_data)
print(f"MRR: {mrr:.3f}")  # 0.611

from dataclasses import dataclass, field
from typing import Any


@dataclass
class RetrievalEvalReport:
    precision_at_k: dict[int, float] = field(default_factory=dict)
    recall_at_k: dict[int, float] = field(default_factory=dict)
    mrr: float = 0.0
    ndcg_at_k: dict[int, float] = field(default_factory=dict)
    n_queries: int = 0


def run_retrieval_eval(
    eval_set: list[dict],   # each: {"question": str, "relevant_ids": set[str]}
    retriever,
    ks: list[int] = [1, 3, 5, 10],
) -> RetrievalEvalReport:
    report = RetrievalEvalReport(n_queries=len(eval_set))
    precision_totals = {k: 0.0 for k in ks}
    recall_totals    = {k: 0.0 for k in ks}
    ndcg_totals      = {k: 0.0 for k in ks}
    rr_total         = 0.0

    for item in eval_set:
        docs = retriever.invoke(item["question"])
        retrieved_ids = [d.metadata.get("id", d.page_content[:50]) for d in docs]
        relevant_ids  = item["relevant_ids"]

        for k in ks:
            precision_totals[k] += precision_at_k(retrieved_ids, relevant_ids, k)
            recall_totals[k]    += recall_at_k(retrieved_ids, relevant_ids, k)
            binary_relevance     = {rid: 1.0 for rid in relevant_ids}
            ndcg_totals[k]      += ndcg_at_k(retrieved_ids, binary_relevance, k)

        rr_total += reciprocal_rank(retrieved_ids, relevant_ids)

    n = len(eval_set)
    report.precision_at_k = {k: round(v / n, 3) for k, v in precision_totals.items()}
    report.recall_at_k    = {k: round(v / n, 3) for k, v in recall_totals.items()}
    report.ndcg_at_k      = {k: round(v / n, 3) for k, v in ndcg_totals.items()}
    report.mrr            = round(rr_total / n, 3)
    return report

import json
from pathlib import Path
from langchain_core.documents import Document

# Step 1: Define representative questions covering your use cases
