# Step 2: Retrieve candidates and export for human labeling
def export_for_labeling(questions: list[str], retriever, output_path: str, k: int = 10):
    records = []
    for question in questions:
        docs = retriever.invoke(question)[:k]
        records.append({
            "question": question,
            "candidates": [
                {
                    "id": doc.metadata.get("id", f"doc_{i}"),
                    "content": doc.page_content,
                    "source": doc.metadata.get("source", ""),
                    "relevant": None,  # human fills in: true / false / 0-3
                }
                for i, doc in enumerate(docs)
            ]
        })
    Path(output_path).write_text(json.dumps(records, indent=2))
    print(f"Exported {len(records)} questions to {output_path}")


# Step 3: Load labeled eval set
def load_eval_set(labeled_path: str) -> list[dict]:
    records = json.loads(Path(labeled_path).read_text())
    return [
        {
            "question": r["question"],
            "relevant_ids": {
                c["id"] for c in r["candidates"]
                if c["relevant"] is True or c["relevant"] == 1
            },
        }
        for r in records
    ]
